mapper.select:
select * from classroom
where classroom_id not in (
    select distinct c.classroom_id
    from course c
    where c.weekday = #{dayOfWeek}
    and not (c.end_time <= #{startTime} or c.start_time >= #{endTime})
)
and classroom_id not in (
    select distinct co.classroom_id
    from classroom_occupy co
    where co.date = #{date}
    and not (co.end_time <= #{startTime} or co.start_time >= #{endTime})
)

select c.classroom_id, c.building_id, b.building_name as buildingName,
       c.room_number, c.floor, c.capacity, c.has_media as hasMedia, c.status
from classroom c
left join building b on c.building_id = b.building_id
where classroom_id not in (
    select distinct cr.classroom_id
    from course cr
    where cr.weekday = #{dayOfWeek}
    and not (cr.end_time <= #{startTime} or cr.start_time >= #{endTime})
)
and classroom_id not in (
    select distinct co.classroom_id
    from classroom_occupy co
    where co.date = #{date}
    and not (co.end_time <= #{startTime} or co.start_time >= #{endTime})
)

    and c.building_id = #{buildingId}


    and c.floor = #{floor}


    and c.capacity >= #{minCapacity}


    and c.has_media = #{hasMedia}

order by c.capacity desc

select c.*, b.building_name as buildingName from classroom c
left join building b on c.building_id = b.building_id


        and c.building_id = #{buildingId}


        and c.status = #{status}


order by c.building_id, c.room_number

mapper.update:
update classroom
building_id = #{buildingId}, room_number = #{roomNumber}, floor = #{floor}, capacity = #{capacity}, has_media = #{hasMedia}, status = #{status},
where classroom_id = #{classroomId}
